const WebSocket = require('ws');

const wss = new WebSocket.Server({ port: 8080 });

wss.on('connection', (ws) => {
    ws.on('message', (message) => {
        try {
            const command = JSON.parse(message);
            processCommand(command);
        } catch (error) {
            console.error('Invalid message:', error);
        }
    });
});

function processCommand(command) {
    switch (command.type) {
        case 'build':
            buildUnit(command.player, command.unitType);
            break;
        case 'attack':
            attackTarget(command.player, command.targetId);
            break;
        case 'move':
            moveUnits(command.player, command.units, command.destination);
            break;
        default:
            console.error('Unknown command type:', command.type);
    }
}

function buildUnit(player, unitType) {
    // Logic to build a unit for the player
    console.log(`${player} is building a ${unitType}`);
}

function attackTarget(player, targetId) {
    // Logic to attack a target for the player
    console.log(`${player} is attacking target ${targetId}`);
}

function moveUnits(player, units, destination) {
    // Logic to move units for the player
    console.log(`${player} is moving units ${units} to ${destination}`);
}